omments":4,"created_at":"2021-03-24T08:19:40Z","updated_at":"2022-09-07T06:20:55Z","closed_at":"2022-09-05T22:27:11Z","author_association":"CONTRIBUTOR","active_lock_reason":null,"body":"From [discourse](https://discourse.julialang.org/t/why-does-this-ccall-segfault/57690?u=jw3126). The following code segfaults for me:

```julia
C = """
typedef struct CParticle {
    double charge;
    double E;
    double weight;
} CParticle;


void simulate(void (*f)(CParticle x)) {
    CParticle cp;
    cp.charge = 0;
    cp.E = 1;
    cp.weight = 2;
    (*f)(cp);
    return;
}

"""

struct CParticle
    charge::Cdouble
    E::Cdouble
    weight::Cdouble
end

write("lib.c", C)
run(`gcc -c -fPIC lib.c -o lib.o`)
run(`gcc -shared lib.o -o lib.so`)
lib = "./lib.so"

function main()
    ret = CParticle[]
    f = x::CParticle -> (push!(ret, x); nothing)
    f_c = @cfunction $f Cvoid (CParticle,)
    GC.@preserve ret f f_c begin # AFAICT I don't need to GC.@preserver here
        @ccall lib.simulate(f_c::Ptr{Cvoid})::Cvoid
    end
    @show ret
end

main()

```
I read the [manual](https://docs.julialang.org/en/v1/manual/calling-c-and-fortran-code/#Calling-C-and-Fortran-Code) and in particular the section [about closures](https://docs.julialang.org/en/v1/manual/calling-c-and-fortran-code/#Closure-cfunctions), but I am still not sure where the error lies.
 It works, if I do one of the following:
* make the `CParticle struct` smaller e.g. only `charge + weight` fields 
* execute the `main` code globally
* don't call `push!` in the callback

@Gnimuc pointed out workarounds, but it is still unclear why this happens, and would be nice to fix it or document it. I can help with the latter.","reactions":{"url":"https://api.github.com/repos/JuliaLang/julia/issues/40164/reactions","total_count":0,"+1":0,"-1":0,"laugh":0,"hooray":0,"confused":0,"heart":0,"rocket":0,"eyes":0},"timeline_url":"https://api.github.com/repos/JuliaLang/julia/issues/40164/timeline","performed_via_github_app":null,"state_reason":"completed"},"comment":{"url":"https://api.github.com/repos/JuliaLang/julia/issues/comments/1238956759","html_url":"https://github.com/JuliaLang/julia/issues/40164#issuecomment-1238956759","issue_url":"https://api.github.com/repos/JuliaLang/julia/issues/40164","id":1238956759,"node_id":"IC_kwDOABkWpM5J2PrX","user":{"login":"jw3126","id":7261506,"node_id":"MDQ6VXNlcjcyNjE1MDY=","avatar_url":"https://avatars.githubusercontent.com/u/7261506?v=4","gravatar_id":"","url":"https://api.github.com/users/jw3126","html_url":"https://github.com/jw3126","followers_url":"https://api.github.com/users/jw3126/followers","following_url":"https://api.github.com/users/jw3126/following{/other_user}","gists_url":"https://api.github.com/users/jw3126/gists{/gist_id}","starred_url":"https://api.github.com/users/jw3126/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/jw3126/subscriptions","organizations_url":"https://api.github.com/users/jw3126/orgs","repos_url":"https://api.github.com/users/jw3126/repos","events_url":"https://api.github.com/users/jw3126/events{/privacy}","received_events_url":"https://api.github.com/users/jw3126/received_events","type":"User","site_admin":false},"created_at":"2022-09-07T06:20:55Z","updated_at":"2022-09-07T06:20:55Z","author_association":"CONTRIBUTOR","body":"Works for me thanks @troels and everybody else for fixing this.","reactions":{"url":"https://api.github.com/repos/JuliaLang/julia/issues/comments/1238956759/reactions","total_count":0,"+1":0,"-1":0,"laugh":0,"hooray":0,"conf